mod slice_x2_probe {
    //! Instrumentation: count how often the host-loop
    //! `execute_with_inputs` falls back to the dispatch-loop branch for
    //! cross-loop JUMP exits.  In-code `closing_jump` work will keep
    //! shrinking this counter until the branch can be deleted.
    use std::sync::atomic::{AtomicUsize, Ordering};

    pub static EXECUTE_WITH_INPUTS_HITS: AtomicUsize = AtomicUsize::new(0);

    pub fn record_execute_with_inputs_hit() {
        EXECUTE_WITH_INPUTS_HITS.fetch_add(1, Ordering::Relaxed);
    }

    struct ReporterGuard;

    impl Drop for ReporterGuard {
        fn drop(&mut self) {
            if std::env::var_os("MAJIT_X2_PROBE").is_some() {
                eprintln!(
                    "[X2-PROBE] execute_with_inputs.external_jump={}",
                    EXECUTE_WITH_INPUTS_HITS.load(Ordering::Relaxed),
                );
            }
        }
    }

    thread_local! {
        static REPORTER: ReporterGuard = const { ReporterGuard };
    }

    pub fn arm_reporter() {
        REPORTER.with(|_| {});
    }
}

/// Whether `MAJIT_LOG` is set, cached at first access.
///
/// `std::env::var_os` acquires a global env lock and walks the env table on
/// every call. The flag never changes after process startup, so checking it
/// from hot dispatch paths (e.g. `run_compiled_code_inner` per bridge hop)
/// shows up in profiles. `LazyLock` caches the boolean.
fn majit_log_enabled() -> bool {
    static ENABLED: std::sync::LazyLock<bool> =
        std::sync::LazyLock::new(|| std::env::var_os("MAJIT_LOG").is_some());
    *ENABLED
}

/// Whether `MAJIT_VERIFY` is set, cached at first access.
fn majit_verify_enabled() -> bool {
    static ENABLED: std::sync::LazyLock<bool> =
        std::sync::LazyLock::new(|| std::env::var_os("MAJIT_VERIFY").is_some());
    *ENABLED
}

use crate::guard::{BridgeData, JitFrameDeadFrame, drop_bridge_payload};

// ── compile.py:665-674 done_with_this_frame singletons ──────────────
//
// Per-result-type `DoneWithThisFrame*` singletons.
// These are now `DescrRef`s holding the metainterp's class-distinct
// `Arc<DoneWithThisFrameDescr*>` / `Arc<ExitFrameWithExceptionDescrRef>`
// instances directly, with no `CraneliftFailDescr` wrapper.  Used as
// fallback identity when the metainterp has not attached its own per-
// cpu singletons via `Backend::set_done_with_this_frame_descr_*`
// (backend-only integration tests and the address fallback in
// `attached_descr_ptrs_with_fallbacks`).  In production
// `match_metainterp_finish_descr` resolves against the per-cpu
// attachments first; these statics only fire when no metainterp is
// attached.

static DONE_WITH_THIS_FRAME_DESCR_INT: std::sync::LazyLock<DescrRef> =
    std::sync::LazyLock::new(|| Arc::new(majit_backend::DoneWithThisFrameDescrInt::new()));

static DONE_WITH_THIS_FRAME_DESCR_FLOAT: std::sync::LazyLock<DescrRef> =
    std::sync::LazyLock::new(|| Arc::new(majit_backend::DoneWithThisFrameDescrFloat::new()));

static DONE_WITH_THIS_FRAME_DESCR_REF: std::sync::LazyLock<DescrRef> =
    std::sync::LazyLock::new(|| Arc::new(majit_backend::DoneWithThisFrameDescrRef::new()));

/// compile.py:658-662 ExitFrameWithExceptionDescrRef singleton.
/// A `DescrRef` holding the metainterp's
/// `ExitFrameWithExceptionDescrRef` directly — no cranelift wrapper.
static EXIT_FRAME_WITH_EXCEPTION_DESCR_REF_CL: std::sync::LazyLock<DescrRef> =
    std::sync::LazyLock::new(|| Arc::new(majit_backend::ExitFrameWithExceptionDescrRef::new()));

static DONE_WITH_THIS_FRAME_DESCR_VOID: std::sync::LazyLock<DescrRef> =
    std::sync::LazyLock::new(|| Arc::new(majit_backend::DoneWithThisFrameDescrVoid::new()));

/// compile.py:665-674 parity: return the singleton FailDescr for a
/// given Finish result type.  Returns the metainterp
/// `DescrRef` directly (no cranelift wrapper).
/// `compile.py:665-674` `make_and_attach_done_descrs` singletons
/// (`_DoneWithThisFrameDescr*`, `ExitFrameWithExceptionDescrRef`,
/// `PropagateExceptionDescr`) bake their `Arc::as_ptr` addresses
/// into the FINISH emit sites (`attached_descr_ptrs_with_fallbacks`)
/// and propagate trampoline.  Singletons are matched ptr-eq against
/// the `CpuDescrAttachments` slot list at the guard-fail boundary
/// (`match_metainterp_finish_descr`) — no process-global Weak
/// registry needed.
fn done_with_this_frame_descr(result_types: &[Type]) -> &'static DescrRef {
    match result_types {
        [Type::Float] => &DONE_WITH_THIS_FRAME_DESCR_FLOAT,
        [Type::Ref] => &DONE_WITH_THIS_FRAME_DESCR_REF,
        [] => &DONE_WITH_THIS_FRAME_DESCR_VOID,
        _ => &DONE_WITH_THIS_FRAME_DESCR_INT,
    }
}

/// Helper for the `fail_descrs: Box<[DescrRef]>` storage.
/// Every entry in a `fail_descrs` collection
/// implements `FailDescr` by construction (codegen pushes singleton
/// `Arc<CraneliftFailDescr>` instances upcast to `DescrRef`); this
/// helper makes the `as_fail_descr()` downcast explicit at every
/// FailDescr-method callsite so the `Box<[DescrRef]>` field can drive
/// trait-method dispatch through the metainterp's `ResumeGuardDescr`
/// without backend-wrapper indirection.
#[inline]
fn as_fd(d: &DescrRef) -> &dyn FailDescr {
    d.as_fail_descr()
        .expect("fail_descrs entries always implement FailDescr")
}

/// Increment per-emission `fail_count` when `fd` owns the slot
/// (Resume-family only — `compile.py:683`
/// `AbstractResumeGuardDescr._attrs_ = ('status',)`).  Singleton
/// FINISH / synthetic descrs (PropagateExceptionDescr,
/// DoneWithThisFrameDescr*, ExitFrameWithExceptionDescrRef) bypass
/// the jitcounter/bridge-retrace machinery and have no counter slot
/// — the trait default panics on them, so this gate keeps the
/// guard-failure dispatcher honest for non-Resume descrs reaching
/// it via the identity-preservation path.
fn maybe_increment_fail_count(fd: &dyn FailDescr) -> u32 {
    if fd.is_resume_guard() || fd.is_resume_guard_copied() {
        fd.increment_fail_count()
    } else {
        0
    }
}

fn attached_descr_ptrs_with_fallbacks(
    attached: majit_backend::AttachedDescrPtrs,
) -> majit_backend::AttachedDescrPtrs {
    fn or_fallback(attached: usize, fallback: i64) -> usize {
        if attached != 0 {
            attached
        } else {
            fallback as usize
        }
    }
    // Singletons are now `DescrRef = Arc<dyn Descr>`.
    // `Arc::as_ptr` returns a *fat* pointer (data + vtable); take the
    // data half via `*const () as i64` so jf_descr identity matches the
    // address the metainterp's `Arc::as_ptr(arc) as *const ()` produces
    // (`history.py:125` per-instance identity is the data pointer, not
    // the vtable pointer).
    majit_backend::AttachedDescrPtrs {
        done_with_this_frame_descr_void: or_fallback(
            attached.done_with_this_frame_descr_void,
            Arc::as_ptr(done_with_this_frame_descr(&[])) as *const () as i64,
        ),
        done_with_this_frame_descr_int: or_fallback(
            attached.done_with_this_frame_descr_int,
            Arc::as_ptr(done_with_this_frame_descr(&[Type::Int])) as *const () as i64,
        ),
        done_with_this_frame_descr_ref: or_fallback(
            attached.done_with_this_frame_descr_ref,
            Arc::as_ptr(done_with_this_frame_descr(&[Type::Ref])) as *const () as i64,
        ),
        done_with_this_frame_descr_float: or_fallback(
            attached.done_with_this_frame_descr_float,
            Arc::as_ptr(done_with_this_frame_descr(&[Type::Float])) as *const () as i64,
        ),
        exit_frame_with_exception_descr_ref: or_fallback(
            attached.exit_frame_with_exception_descr_ref,
            Arc::as_ptr(&*EXIT_FRAME_WITH_EXCEPTION_DESCR_REF_CL) as *const () as i64,
        ),
        propagate_exception_descr: attached.propagate_exception_descr,
    }
}

/// Match `jf_descr_raw` against the metainterp-attached
/// `DoneWithThisFrameDescr*` set on a specific cpu instance.  Returns
/// `Some((metainterp_arc, cranelift_singleton))` when the address is
/// one of the six attached finish descrs; the paired cranelift
/// singleton carries the result_type signature that runtime
/// classifiers (`bridge_ref`, fail_arg_types) expect.
///
/// Parameter-threaded rather than thread-local because
/// `compile.py:665 setattr(cpu, name, descr)` binds the attachment to
/// a specific `cpu` instance — every caller must identify *which* cpu
/// the descr should be resolved against, not consult an ambient slot.
fn match_metainterp_finish_descr(
    jf_descr_raw: i64,
    attachments: &CpuDescrAttachments,
) -> Option<(majit_ir::DescrRef, DescrRef)> {
    let ptr = jf_descr_raw as usize;
    fn check(slot: &Option<majit_ir::DescrRef>, expected: usize) -> Option<majit_ir::DescrRef> {
        slot.as_ref().and_then(|arc| {
            if Arc::as_ptr(arc) as *const () as usize == expected {
                Some(arc.clone())
            } else {
                None
            }
        })
    }
    for (slot, cl_singleton) in [
        (
            &attachments.done_with_this_frame_descr_int,
            &*DONE_WITH_THIS_FRAME_DESCR_INT,
        ),
        (
            &attachments.done_with_this_frame_descr_float,
            &*DONE_WITH_THIS_FRAME_DESCR_FLOAT,
        ),
        (
            &attachments.done_with_this_frame_descr_ref,
            &*DONE_WITH_THIS_FRAME_DESCR_REF,
        ),
        (
            &attachments.done_with_this_frame_descr_void,
            &*DONE_WITH_THIS_FRAME_DESCR_VOID,
        ),
        (
            &attachments.exit_frame_with_exception_descr_ref,
            &*EXIT_FRAME_WITH_EXCEPTION_DESCR_REF_CL,
        ),
    ] {
        if let Some(arc) = check(slot, ptr) {
            // cl_singleton is `&DescrRef` (the metainterp's
            // `Arc<DoneWithThisFrameDescr*>` or
            // `Arc<ExitFrameWithExceptionDescrRef>` directly — no
            // CraneliftFailDescr wrapper).
            return Some((arc, cl_singleton.clone()));
        }
    }
    None
}

// ── JitFrame layout constants (jitframe.py:61-83) ───────────────────
//
// The canonical layout lives in `majit_backend::jitframe`; re-export the
// byte offsets here so uses inside this file stay terse.
use majit_backend::jitframe::{
    BASEITEMOFS, JF_DESCR_OFS, JF_FORCE_DESCR_OFS, JF_FORWARD_OFS, JF_FRAME_OFS, JF_GCMAP_OFS,
    JF_GUARD_EXC_OFS, JF_SAVEDATA_OFS,
};
/// Byte offset of `jf_frame_length` from JitFrame start
/// (`jitframe.py:84` — `jf_frame`'s length word sits at the array base).
const JF_FRAME_LENGTH_OFS: i32 = JF_FRAME_OFS as i32;
/// Byte offset of `jf_frame[0]` from JitFrame start
/// (`jitframe.py:99` — `BASEITEMOFS`: first item follows the length word).
const JF_FRAME_ITEM0_OFS: i32 = JF_FRAME_OFS as i32 + BASEITEMOFS as i32;
/// GC type id for JitFrame objects, assigned at runtime by the frontend
/// that owns the GC type registry (pyre-jit registers OBJECT / W_INT /
/// W_FLOAT before JITFRAME, so the JITFRAME id depends on that ordering
/// and cannot be hard-coded here).
///
/// `u32::MAX` means "not yet registered"; the backend uses this in
/// `ensure_jitframe_type_registered` to set it up lazily with its own
/// custom trace hook, and in `alloc_nursery_no_collect_typed` to pass
/// the correct id to the allocator.
static JITFRAME_GC_TYPE_ID: std::sync::atomic::AtomicU32 =
    std::sync::atomic::AtomicU32::new(u32::MAX);
static JITFRAME_GC_TYPE_ID_IS_EXPLICIT: AtomicBool = AtomicBool::new(false);

/// Override the JITFRAME type id explicitly. Called from the frontend
/// after it has registered its own types so that our nursery allocations
/// (gc.alloc_nursery_no_collect_typed) use the same id that the frontend
/// assigned to the JITFRAME TypeInfo (jitframe.py:48-52).
pub fn set_jitframe_gc_type_id(id: u32) {
    JITFRAME_GC_TYPE_ID.store(id, std::sync::atomic::Ordering::Release);
    JITFRAME_GC_TYPE_ID_IS_EXPLICIT.store(true, std::sync::atomic::Ordering::Release);
}

fn jitframe_gc_type_id() -> u32 {
    JITFRAME_GC_TYPE_ID.load(std::sync::atomic::Ordering::Acquire)
}

fn set_jitframe_gc_type_id_lazy(id: u32) {
    JITFRAME_GC_TYPE_ID.store(id, std::sync::atomic::Ordering::Release);
    JITFRAME_GC_TYPE_ID_IS_EXPLICIT.store(false, std::sync::atomic::Ordering::Release);
}

fn jitframe_gc_type_id_is_explicit() -> bool {
    JITFRAME_GC_TYPE_ID_IS_EXPLICIT.load(std::sync::atomic::Ordering::Acquire)
}

/// Ensure the JITFRAME GC type is registered, and that
/// `JITFRAME_GC_TYPE_ID` reflects the id the GC assigned to it.
///
/// RPython: rgc.register_custom_trace_hook(JITFRAME, jitframe_trace)
/// called from jitframe_allocate (jitframe.py:49).
///
/// Lazy path (no frontend registration): register JITFRAME directly on
/// each allocator and return the runtime-local type id. The `TypeInfo`
/// comes from `majit_backend::jitframe::jitframe_type_info()` so the
/// layout, item size, and custom-trace hook stay in sync with every
/// other consumer of JITFRAME.
fn ensure_jitframe_type_registered(gc: &mut dyn GcAllocator) -> Option<u32> {
    if gc.type_count() == 0 {
        return None; // Stub GC (TrackingGc), no type registry
    }
    if jitframe_gc_type_id_is_explicit() {
        let id = jitframe_gc_type_id();
        assert_ne!(id, u32::MAX, "explicit JITFRAME GC type id missing");
        return Some(id);
    }
    let id = gc.register_type(majit_backend::jitframe::jitframe_type_info());
    set_jitframe_gc_type_id_lazy(id);
    Some(id)
}

/// Follow jf_forward chain to get the final jitframe address.
///
/// RPython jitframe.py:54-57 jitframe_resolve:
///   while frame.jf_forward:
///       frame = frame.jf_forward
///   return frame
fn jitframe_resolve(jf_ptr: *mut i64) -> *mut i64 {
    let mut ptr = jf_ptr;
    loop {
        let forward_addr =
            unsafe { *((ptr as *const u8).add(JF_FORWARD_OFS as usize) as *const usize) };
        if forward_addr == 0 {
            return ptr;
        }
        ptr = forward_addr as *mut i64;
    }
}

