#[derive(Clone)]
struct RegisteredLoopTarget {
    trace_id: u64,
    /// RPython greenkey[1]: bytecode PC of the loop header.
    /// 0 for FINISH traces (no JUMP/Label).
    header_pc: u64,
    /// RPython greenkey hash: function identifier for guard lookup.
    green_key: u64,
    caller_prefix_layout: Option<ExitRecoveryLayout>,
    code_ptr: *const u8,
    /// Frozen after compile — `Box<[T]>` reflects RPython's no-mutation
    /// contract (compile.py:183-203 record_loop_or_bridge).  Position
    /// equals `descr.fail_index` by an invariant asserted at construction.
    fail_descrs: Box<[DescrRef]>,
    /// `FailDescrCell` thin wrappers, one per non-finish `fail_descrs[i]`
    /// position.  `Arc<FailDescrCell>` is a thin pointer (concrete-typed)
    /// so the address baked into JIT code (`jf_descr`) round-trips back
    /// to the cell via `Arc::from_raw` (`majit_ir::recover_fail_descr_cell`)
    /// without a process-global Weak registry.  Keep-alive root is this
    /// field on `CompiledLoop`; the CLT drop releases the JIT code and
    /// the cells together so a stale baked address never outlives its
    /// cell.  Position-aligned with `fail_descrs` (singleton finish
    /// emissions still get a wrapping cell so position equality holds).
    fail_descr_cells: Box<[Arc<majit_ir::FailDescrCell>]>,
    num_inputs: usize,
    num_ref_roots: usize,
    max_output_slots: usize,
    inputarg_types: Vec<Type>,
    /// virtualizable.py:86 read_boxes: number of scalar inputargs
    /// (frame + static fields). First local is at this index.
    num_scalar_inputargs: usize,
    /// pyjitpl.py:3605 — outermost_jitdriver_sd.index_of_virtualizable.
    /// Read from JitCellToken at registration time; -1 when the driver
    /// has no virtualizable.
    index_of_virtualizable: i32,
    /// `rpython/jit/backend/model.py:292-338` `CompiledLoopToken` — the
    /// per-loop metadata RPython `handle_call_assembler` (rewrite.py:665-
    /// 695) reads as `loop_token.compiled_loop_token`. Sources
    /// `_ll_initial_locs` (`regalloc.py:861-871`) and `frame_info`
    /// (`jitframe.py:30-40`) for `call_assembler_callee_locs`. Arc
    /// continuity across pending → real registration is preserved by
    /// adopting the pending Arc onto `token.compiled_loop_token` in
    /// `register_call_assembler_target`.
    compiled_loop_token: Arc<CompiledLoopToken>,
    /// `compile.py:665 setattr(cpu, name, descr)` — heap-stable clone of
    /// the owning `CraneliftBackend`'s per-cpu descr attachments.  Kept
    /// here so `execute_registered_loop_target` (a free fn reached from
    /// extern-C trampolines) can pass a snapshot into
    /// `match_metainterp_finish_descr` without a `&self` receiver.
    cpu_attachments: CpuDescrHandle,
}

unsafe impl Send for RegisteredLoopTarget {}
unsafe impl Sync for RegisteredLoopTarget {}

// history.py:470-499 TargetToken._ll_loop_code parity.
// Maps TargetToken descriptor identity (Arc::as_ptr) to the loop entry
// point needed to re-enter the target from an external JUMP exit.
// assembler.py:2456-2462 closing_jump reads `target_token._ll_loop_code`
// directly for cross-loop JMPs; since Cranelift can't emit raw inter-
// function JMPs, the dispatcher reads this entry and invokes
// run_compiled_code on the target's code_ptr.
#[derive(Clone)]
struct LoopTargetEntry {
    code_ptr: *const u8,
    /// Frozen after compile — `Box<[T]>` reflects RPython's no-mutation
    /// contract (compile.py:183-203 record_loop_or_bridge).
    fail_descrs: Box<[DescrRef]>,
    /// Position-aligned `FailDescrCell` wrappers — see `CompiledLoop`.
    fail_descr_cells: Box<[Arc<majit_ir::FailDescrCell>]>,
    num_inputs: usize,
    num_ref_roots: usize,
    max_output_slots: usize,
}

unsafe impl Send for LoopTargetEntry {}
unsafe impl Sync for LoopTargetEntry {}

thread_local! {
    /// Per-thread `TargetToken._ll_loop_code` registry. Same TODO
    /// rationale as `CALL_ASSEMBLER_TARGETS` — pyre's u64-keyed
    /// trampoline dispatch needs a runtime lookup that RPython avoids by
    /// reading `target_token._ll_loop_code` off the descr directly.
    /// Thread-local matches pyre's single-threaded JIT execution and
    /// aligns with the adjacent `CALL_ASSEMBLER_TARGETS` migration.
    static LOOP_TARGET_REGISTRY: RefCell<VecAssoc<usize, LoopTargetEntry>> =
        RefCell::new(VecAssoc::new());
}

/// history.py:470 TargetToken identity key: Arc allocation address.
/// Mirrors PyPy's `target_tokens_currently_compiling[descr] = None`
/// dict keyed by descriptor object identity.
fn register_loop_target(descr: &majit_ir::DescrRef, entry: LoopTargetEntry) {
    let key = majit_ir::descr_identity(descr);
    LOOP_TARGET_REGISTRY.with(|r| r.borrow_mut().insert(key, entry));
}

fn lookup_loop_target(descr: &majit_ir::DescrRef) -> Option<LoopTargetEntry> {
    let key = majit_ir::descr_identity(descr);
    LOOP_TARGET_REGISTRY.with(|r| r.borrow().get(&key).cloned())
}

fn deadframe_layout(frame: &DeadFrame) -> Option<FailDescrLayout> {
    let jf = frame.data.downcast_ref::<JitFrameDeadFrame>()?;
    let descr_ref: DescrRef = jf.fail_descr.clone();
    let fd = jf
        .fail_descr
        .as_fail_descr()
        .expect("JitFrameDeadFrame.fail_descr always implements FailDescr");
    // Use the descr's structural `fail_index` / `trace_id` to preserve
    // pre-7-Tβ14a behavior — deadframe lookups did not have access to
    // a runtime per-trace position so the descr-internal values flow
    // through.  For singleton FINISH descrs this means u32::MAX / 0,
    // matching the prior `descr.layout()` semantics.
    let fail_index = fd.fail_index();
    let trace_id = fd.trace_id();
    let mut layout = fail_descr_layout(&descr_ref, fail_index, trace_id);

    // If a `wrap_call_assembler_deadframe_with_caller_prefix`
    // call has stashed a caller-prefix layout on this deadframe, prepend
    // it to the descr's own recovery layout (the same composition the
    // overlay descr machinery used to bake at wrap time).  Replays the
    // PyPy `assembler_call_helper` parent-frame chain reconstruction
    // (`pyjitpl.MetaInterp.framestack` walk) at deopt time instead of
    // pre-baking.
    if let Some(caller_layout) = &jf.call_assembler_caller_layout {
        let inner = layout
            .recovery_layout
            .clone()
            .or_else(|| deadframe_recovery_layout_for_call_assembler(&layout));
        if let Some(inner) = inner {
            let prefixed = inner.prefixed_by(Some(caller_layout));
            layout.frame_stack = Some(prefixed.frames.clone());
            layout.recovery_layout = Some(prefixed);
        }
    }
    Some(layout)
}

fn deadframe_recovery_layout_for_call_assembler(
    layout: &FailDescrLayout,
) -> Option<ExitRecoveryLayout> {
    layout.recovery_layout.clone().or_else(|| {
        layout.trace_info.as_ref().map(|trace_info| {
            identity_recovery_layout(
                layout.trace_id,
                trace_info.header_pc,
                None, // no per-guard resume_pc available here
                trace_info.source_guard,
                &layout.fail_arg_types,
                None,
            )
        })
    })
}

fn caller_prefix_recovery_layout(
    trace_id: u64,
    header_pc: u64,
    source_guard: Option<(u64, u32)>,
    slot_types: &[Type],
    inputs: &[i64],
    caller_prefix_layout: Option<&ExitRecoveryLayout>,
) -> ExitRecoveryLayout {
    ExitRecoveryLayout {
        vable_array: Vec::new(),
        vref_array: Vec::new(),
        frames: vec![ExitFrameLayout {
            trace_id: Some(trace_id),
            header_pc: Some(header_pc),
            source_guard,
            pc: header_pc,
            // Placeholder: this caller-prefix identity layout is replaced by
            // the resume_layout-derived layout via
            // `compile::patch_guard_recovery_layouts_for_trace`
            // (compile.rs:1596) before any guard can fire.  The
            // resume_layout carries the authoritative jitcode_index
            // threaded from `Snapshot::single_frame`.
            jitcode_index: 0,
            slots: slot_types
                .iter()
                .enumerate()
                .map(|(slot, _)| {
                    inputs
                        .get(slot)
                        .copied()
                        .map(ExitValueSourceLayout::Constant)
                        .unwrap_or(ExitValueSourceLayout::Unavailable)
                })
                .collect(),
            slot_types: Some(slot_types.to_vec()),
        }],
        virtual_layouts: Vec::new(),
        pending_field_layouts: Vec::new(),
    }
    .prefixed_by(caller_prefix_layout)
}

fn wrap_call_assembler_deadframe_with_caller_prefix(mut frame: DeadFrame) -> DeadFrame {
    // Stash the caller-prefix layout in a side-channel on
    // `JitFrameDeadFrame` instead of synthesising an overlay descr and
    // stamping it onto `jf_descr`.  `deadframe_layout` reads the side-
    // channel and prepends it to the callee descr's own recovery layout
    // on demand.  The deadframe's `fail_descr` keeps the callee's own
    // Arc identity, so `cpu.get_latest_descr(deadframe)` returns the
    // callee descr (`llmodel.py:411-419` get_latest_descr parity), and
    // the raw `jf_descr` slot still carries a `FailDescrCell` thin
    // pointer resolvable via `recover_fail_descr_cell`,
    // with no overlay descr needed.
    let Some(jf) = frame.data.downcast_mut::<JitFrameDeadFrame>() else {
        // Fallback: return as-is (should not happen after FrameData removal).
        return frame;
    };
    if jf.call_assembler_caller_layout.is_some() {
        // Nested wrap on the same deadframe would compose caller prefixes
        // incorrectly; the dispatch design guarantees a single wrap call
        // per CALL_ASSEMBLER deadframe interception.
        panic!(
            "wrap_call_assembler_deadframe_with_caller_prefix: deadframe \
             already carries a call_assembler_caller_layout"
        );
    }
    let caller_layout = with_current_call_assembler_caller_context(|maybe_ctx| {
        let ctx = maybe_ctx.expect(
            "X3-C: CallAssemblerCallerContextGuard must be in scope at \
             every wrap_call_assembler_deadframe_with_caller_prefix call \
             site",
        );
        caller_prefix_recovery_layout(
            ctx.trace_id,
            ctx.header_pc,
            ctx.source_guard,
            &ctx.input_types,
            &ctx.inputs,
            ctx.caller_prefix_layout.as_ref(),
        )
    });
    jf.call_assembler_caller_layout = Some(caller_layout);
    frame
}

/// Caller-side data captured at a CALL_ASSEMBLER site so the callee's
/// guard-failure deopt can reconstruct the caller's frame on demand.
///
/// PyPy carries this implicitly: an assembler call is a regular machine
/// call, and the caller's host stack frame is the deopt's reconstruction
/// anchor (`pyjitpl.MetaInterp.framestack` mirrors it for blackhole
/// resume; `portal_call_depth` counts the recursion).  cranelift's host-
/// loop dispatch (`execute_with_inputs`) cannot piggyback on the host
/// stack — the live host frame is the dispatch loop, not the caller's
/// compiled code — so the equivalent state must be captured explicitly.
///
/// This struct mirrors the six values
/// `wrap_call_assembler_deadframe_with_caller_prefix` already takes one
/// at a time.  The struct itself disappears together with
/// `execute_with_inputs` once the dispatch loop collapses to a
/// single-call `execute_token` (PyPy `llmodel.execute_token`).
#[derive(Clone)]
struct CallAssemblerCallerContext {
    trace_id: u64,
    header_pc: u64,
    source_guard: Option<(u64, u32)>,
    input_types: Vec<Type>,
    inputs: Vec<i64>,
    caller_prefix_layout: Option<ExitRecoveryLayout>,
}

impl CallAssemblerCallerContext {
    fn from_compiled_loop(compiled: &CompiledLoop, inputs: &[i64]) -> Self {
        Self {
            trace_id: compiled.trace_id,
            header_pc: compiled.header_pc,
            source_guard: None,
            input_types: compiled.input_types.clone(),
            inputs: inputs.to_vec(),
            caller_prefix_layout: compiled.caller_prefix_layout.clone(),
        }
    }

    fn from_bridge_data(bridge: &BridgeData, inputs: &[i64]) -> Self {
        Self {
            trace_id: bridge.trace_id,
            header_pc: bridge.header_pc,
            source_guard: Some(bridge.source_guard),
            input_types: bridge.input_types.clone(),
            inputs: inputs.to_vec(),
            caller_prefix_layout: bridge.caller_prefix_layout.clone(),
        }
    }

    fn from_registered_loop_target(target: &RegisteredLoopTarget, inputs: &[i64]) -> Self {
        Self {
            trace_id: target.trace_id,
            header_pc: target.header_pc,
            source_guard: None,
            input_types: target.inputarg_types.clone(),
            inputs: inputs.to_vec(),
            caller_prefix_layout: target.caller_prefix_layout.clone(),
        }
    }
}

thread_local! {
    /// Host-side caller stack scaffold for CALL_ASSEMBLER deopt
    /// reconstruction.  Each entry corresponds to one in-progress host-
    /// loop iteration in `execute_with_inputs` / `execute_bridge` /
    /// `execute_registered_loop_target`; the top of the stack is the
    /// caller of any CALL_ASSEMBLER deadframe interception currently
    /// being processed.
    ///
    /// The producer (CallAssemblerCallerContextGuard at every wrap site)
    /// and the consumer (`wrap_call_assembler_deadframe_with_caller_prefix`)
    /// are connected via this thread-local.  Thread-local
    /// matches pyre's single-threaded JIT execution, mirroring the
    /// surrounding `LOOP_TARGET_REGISTRY` shape.
    static CALL_ASSEMBLER_CALLER_STACK: RefCell<Vec<CallAssemblerCallerContext>> =
        const { RefCell::new(Vec::new()) };
}

fn push_call_assembler_caller_context(ctx: CallAssemblerCallerContext) {
    CALL_ASSEMBLER_CALLER_STACK.with(|s| s.borrow_mut().push(ctx));
}

fn pop_call_assembler_caller_context() -> Option<CallAssemblerCallerContext> {
    CALL_ASSEMBLER_CALLER_STACK.with(|s| s.borrow_mut().pop())
}

#[allow(dead_code)] // consumed by deopt callback
fn current_call_assembler_caller_context() -> Option<CallAssemblerCallerContext> {
    CALL_ASSEMBLER_CALLER_STACK.with(|s| s.borrow().last().cloned())
}

/// Borrow-form reader for the stack-top `CallAssemblerCallerContext`.
/// Lets the dual-verify check in
/// `wrap_call_assembler_deadframe_with_caller_prefix` reconstruct the
/// caller-prefix layout without cloning the context's Vec fields.
fn with_current_call_assembler_caller_context<F, R>(f: F) -> R
where
    F: FnOnce(Option<&CallAssemblerCallerContext>) -> R,
{
    CALL_ASSEMBLER_CALLER_STACK.with(|s| f(s.borrow().last()))
}

/// RAII guard that pushes a `CallAssemblerCallerContext` on construction
/// and pops on drop.  Used at every `wrap_call_assembler_deadframe_with_
/// caller_prefix` call site so the wrap consumer can read the caller's
/// data off the stack.
struct CallAssemblerCallerContextGuard;

impl CallAssemblerCallerContextGuard {
    fn push(ctx: CallAssemblerCallerContext) -> Self {
        push_call_assembler_caller_context(ctx);
        Self
    }
}

impl Drop for CallAssemblerCallerContextGuard {
    fn drop(&mut self) {
        pop_call_assembler_caller_context();
    }
}

/// Global exception state for JIT-compiled code.
/// pyre is no-GIL single-threaded, so global statics are safe and allow
/// GUARD_NO_EXCEPTION to emit a direct memory load instead of a TLS call.
static JIT_EXC_VALUE: std::sync::atomic::AtomicI64 = std::sync::atomic::AtomicI64::new(0);
static JIT_EXC_TYPE: std::sync::atomic::AtomicI64 = std::sync::atomic::AtomicI64::new(0);

/// Return the address of JIT_EXC_VALUE for direct memory load in JIT code.
pub fn jit_exc_value_addr() -> usize {
    &JIT_EXC_VALUE as *const _ as usize
}

/// Return the address of JIT_EXC_TYPE for direct memory store in JIT code.
fn jit_exc_type_addr() -> usize {
    &JIT_EXC_TYPE as *const _ as usize
}

thread_local! {
    /// Thread-local reference storage for JIT-compiled code.
    ///
    /// Mirrors RPython's `rpy_threadlocalref` — an array of integer-sized slots
    /// indexed by offset. The interpreter stores per-thread state here (e.g.,
    /// the current action flag, signal handler data, etc.).
    ///
    /// Slots are accessed via THREADLOCALREF_GET opcode.
    static JIT_THREADLOCAL_SLOTS: RefCell<Vec<i64>> = const { RefCell::new(Vec::new()) };
}

// ── Exception state shims called from JIT-compiled code ──

/// Clear the current exception state.
pub extern "C" fn jit_exc_clear() {
    JIT_EXC_VALUE.store(0, std::sync::atomic::Ordering::Relaxed);
    JIT_EXC_TYPE.store(0, std::sync::atomic::Ordering::Relaxed);
}

/// llmodel.py:194-199 _store_exception parity: set exception state.
///
/// `value` must be a valid OBJECTPTR (or 0). The exception class is
/// derived from `value.typeptr` (offset 0), matching RPython's invariant
/// that pos_exception() == ptr2int(pos_exc_value().typeptr).
pub fn jit_exc_raise(value: i64) {
    let exc_type = if value == 0 {
        0
    } else {
        unsafe { *(value as *const i64) }
    };
    JIT_EXC_VALUE.store(value, std::sync::atomic::Ordering::Relaxed);
    JIT_EXC_TYPE.store(exc_type, std::sync::atomic::Ordering::Relaxed);
}

/// Check if an exception is currently pending.
pub fn jit_exc_is_pending() -> bool {
    JIT_EXC_VALUE.load(std::sync::atomic::Ordering::Relaxed) != 0
}

/// RPython cpu.grab_exc_value parity: read exception class from TLS.
pub fn jit_exc_class_raw() -> i64 {
    JIT_EXC_TYPE.load(std::sync::atomic::Ordering::Relaxed)
}

/// RPython cpu.grab_exc_value parity: read exception value from TLS.
pub fn jit_exc_value_raw() -> i64 {
    JIT_EXC_VALUE.load(std::sync::atomic::Ordering::Relaxed)
}

// ── Thread-local reference access shims ──

/// Read a thread-local slot at the given offset.
///
/// Called from JIT-compiled code for THREADLOCALREF_GET operations.
/// The offset is in bytes (divided by 8 to get the slot index).
extern "C" fn jit_threadlocalref_get(offset: i64) -> i64 {
    JIT_THREADLOCAL_SLOTS.with(|slots| {
        let slots = slots.borrow();
        let idx = (offset / 8) as usize;
        slots.get(idx).copied().unwrap_or(0)
    })
}

/// Write a value to a thread-local slot at the given offset.
///
/// Called by the interpreter to set up thread-local state before entering
/// JIT-compiled code.
pub fn jit_threadlocalref_set(offset: i64, value: i64) {
    JIT_THREADLOCAL_SLOTS.with(|slots| {
        let mut slots = slots.borrow_mut();
        let idx = (offset / 8) as usize;
        if idx >= slots.len() {
            slots.resize(idx + 1, 0);
        }
        slots[idx] = value;
    });
}

/// Get the base pointer for thread-local slots.
/// Returns 0 since we use callback-based access.
pub fn jit_threadlocalref_base() -> *const i64 {
    JIT_THREADLOCAL_SLOTS.with(|slots| {
        let slots = slots.borrow();
        if slots.is_empty() {
            std::ptr::null()
        } else {
            slots.as_ptr()
        }
    })
}

// ── GIL release/reacquire shims ──

/// User-installable hook for GIL release before CallReleaseGil.
static GIL_RELEASE_HOOK: OnceLock<Box<dyn Fn() + Send + Sync>> = OnceLock::new();
/// User-installable hook for GIL reacquire after CallReleaseGil.
static GIL_REACQUIRE_HOOK: OnceLock<Box<dyn Fn() + Send + Sync>> = OnceLock::new();

/// Install custom GIL release/reacquire hooks.
pub fn set_gil_hooks(
    release: impl Fn() + Send + Sync + 'static,
    reacquire: impl Fn() + Send + Sync + 'static,
) {
    let _ = GIL_RELEASE_HOOK.set(Box::new(release));
    let _ = GIL_REACQUIRE_HOOK.set(Box::new(reacquire));
}

extern "C" fn jit_release_gil_shim() {
    if let Some(hook) = GIL_RELEASE_HOOK.get() {
        hook();
    }
}

extern "C" fn jit_reacquire_gil_shim() {
    if let Some(hook) = GIL_REACQUIRE_HOOK.get() {
        hook();
    }
}

// ── rewrite.py:489 parity: inject str_descr/unicode_descr ──
//
// Token semantics come from `symbolic.get_array_token(rstr.STR/UNICODE, ...)`
// and `symbolic.get_field_token(rstr.STR/UNICODE, 'hash', ...)` (see
// `rpython/jit/backend/llsupport/symbolic.py:7,29`). See the matching
// comment in `majit-backend-dynasm/src/runner.rs` for full layout
// rationale — both backends mirror the upstream rstr layout.
//
// TODO: These constants assume PyPy's inline
// `rstr.STR` layout `[hash | len | chars...]`.  Pyre's `W_StrObject`
// stores chars behind `*mut String` (a `repr(Rust)` type whose
// internal layout is not guaranteed).  STRLEN is correct: it reads
// `byte_len`/`len` via `len_descr().offset()`.  STRGETITEM's
// compiled path uses `base + basesize + index` addressing against
// the inline chars, which would produce wrong reads against
// `W_StrObject`.  In practice the compiled STRGETITEM is not
// reached — the optimizer constant-folds it (`PyreCpu::bh_strgetitem`)
// or routes through residual helpers.  Fixing requires either
// (a) inlining chars in `W_StrObject` like `rstr.STR`, or
// (b) emitting a 2-load indirection in the backend.

/// `symbolic.get_field_token(rstr.STR/UNICODE, 'hash', ...).offset`.
const BUILTIN_STRING_HASH_OFFSET: usize = 0;
/// `symbolic.get_field_token(..., 'hash', ...).size` — assert == WORD at
/// rewrite.py:286,292.
const BUILTIN_STRING_HASH_SIZE: usize = std::mem::size_of::<usize>();
/// `symbolic.get_array_token(...).ofs_length`.
const BUILTIN_STRING_LEN_OFFSET: usize = std::mem::size_of::<usize>();
/// STR token `basesize` — header + extra_item_after_alloc.
const BUILTIN_STR_TOKEN_BASE_SIZE: usize = 2 * std::mem::size_of::<usize>() + 1;
/// UNICODE token `basesize` — header only.
const BUILTIN_UNICODE_TOKEN_BASE_SIZE: usize = 2 * std::mem::size_of::<usize>();
/// Byte offset of the first `chars[]` slot at runtime, for backend tests
/// (`BUILTIN_STR_TOKEN_BASE_SIZE - 1`: subtract the extra_item_after_alloc
/// since tests address char[0] directly).
#[cfg(test)]
const BUILTIN_STRING_CHARS_OFFSET: usize = BUILTIN_STR_TOKEN_BASE_SIZE - 1;

// ---------------------------------------------------------------------------
// Helpers (free functions to avoid borrow conflicts)
// ---------------------------------------------------------------------------

thread_local! {
    /// regalloc.py:140-181 RegisterManager.{reg_bindings, longevity} parity:
    /// RPython tracks an explicit Box → register/spill-slot dict so the
    /// allocator can hand out fresh slots for each Box independently of any
    /// underlying numbering. majit's `OpRef` is a position rather than an
    /// identity, so when Phase 2 OpRefs end up sparse (Box identity put
    /// Phase 2 starting at `phase1_high_water`) the previous
    /// `Variable::from_u32(opref.raw())` mapping inflated Cranelift's Variable
    /// space with dummy declarations to fill the gaps. The thread-local
    /// map below replaces that with a sparse-OpRef → dense-Variable lookup
    /// populated during `do_compile`'s declaration loop.
    static OPREF_VAR_MAP: std::cell::RefCell<Option<majit_ir::VecAssoc<u32, Variable>>> =
        const { std::cell::RefCell::new(None) };
}

/// RAII guard that restores `OPREF_VAR_MAP` on Drop, so nested compiles
/// (bridge compilation re-entry) don't leak the inner compile's mapping
/// past its scope. The early-return branches in do_compile then don't
/// need explicit cleanup hooks.
struct OprefVarMapGuard {
    saved: Option<majit_ir::VecAssoc<u32, Variable>>,
}

impl Drop for OprefVarMapGuard {
    fn drop(&mut self) {
        let saved = self.saved.take();
        OPREF_VAR_MAP.with(|cell| {
            *cell.borrow_mut() = saved;
        });
    }
}

fn var(idx: u32) -> Variable {
    OPREF_VAR_MAP.with(|cell| {
        if let Some(map) = cell.borrow().as_ref() {
            if let Some(&v) = map.get(&idx) {
                return v;
            }
        }
        // Pre-declaration fallback: callers that materialise a Variable
        // before do_compile populates the map (e.g. test fixtures, helper
        // utilities) keep the legacy dense mapping. This branch is also
        // taken in the do_compile pre-declaration window before the loop
        // below installs OPREF_VAR_MAP.
        Variable::from_u32(idx)
    })
}

/// Convert a slice of Values to a Vec of BlockArgs for Cranelift 0.130 branch instructions.
fn block_args(vals: &[CValue]) -> Vec<BlockArg> {
    vals.iter().copied().map(BlockArg::from).collect()
}

/// Reinterpret `val` as `want` via `bitcast`, but only when the types
/// actually differ. Scalar float values are carried either as `F64` (kept
/// live in an FP register across a loop back-edge) or as `I64` (boxed raw
/// bits at frame/guard/call boundaries) depending on the variable's declared
/// type; this reconciles the two at a boundary without emitting a redundant
/// GPR<->FP move (`fmov`) when the value already has the wanted type.
fn coerce_ty(
    builder: &mut FunctionBuilder,
    val: CValue,
    want: cranelift_codegen::ir::Type,
) -> CValue {
    if builder.func.dfg.value_type(val) == want {
        val
    } else {
        builder.ins().bitcast(want, MemFlags::new(), val)
    }
}

/// Cranelift carrier type for a scalar OpRef: `F64` for float-typed boxes
/// (kept in an FP register), `I64` for everything else. Vector OpRefs are
/// classified separately via `vec_oprefs` and never reach here.
fn cl_type_for_opref(opref: OpRef) -> cranelift_codegen::ir::Type {
    match opref.ty() {
        Some(Type::Float) => cl_types::F64,
        _ => cl_types::I64,
    }
}

/// Build block args for a branch into `target`, coercing each value to the
/// corresponding block-param type. A float value delivered as boxed `I64`
/// (e.g. an inline float constant) is reinterpreted to the param's `F64`
/// type, and vice versa, so an `F64`-typed loop-carried param never receives
/// a mismatched `I64` arg.
fn block_args_to(
    builder: &mut FunctionBuilder,
    target: cranelift_codegen::ir::Block,
    vals: &[CValue],
) -> Vec<BlockArg> {
    let want: Vec<cranelift_codegen::ir::Type> = builder
        .func
        .dfg
        .block_params(target)
        .iter()
        .map(|&p| builder.func.dfg.value_type(p))
        .collect();
    vals.iter()
        .enumerate()
        .map(|(i, &v)| {
            let t = want.get(i).copied().unwrap_or(cl_types::I64);
            BlockArg::from(coerce_ty(builder, v, t))
        })
        .collect()
}

/// Whether to use native SIMD (I64X2/F64X2) for Vec* codegen.
/// When false, falls back to scalar emulation.
const USE_NATIVE_SIMD: bool = true;

/// Returns true if `opcode` is a Vec* opcode that produces a vector-typed value
/// (I64X2 or F64X2). VecUnpack* opcodes produce scalars, so they return false.
/// Guard/void opcodes also return false.
fn is_vec_producing_opcode(opcode: OpCode) -> bool {
    matches!(
        opcode,
        OpCode::VecIntAdd
            | OpCode::VecIntSub
            | OpCode::VecIntMul
            | OpCode::VecIntAnd
            | OpCode::VecIntOr
            | OpCode::VecIntXor
            | OpCode::VecFloatAdd
            | OpCode::VecFloatSub
            | OpCode::VecFloatMul
            | OpCode::VecFloatTrueDiv
            | OpCode::VecFloatNeg
            | OpCode::VecFloatAbs
            | OpCode::VecFloatXor
            | OpCode::VecI
            | OpCode::VecF
            | OpCode::VecPackI
            | OpCode::VecPackF
            | OpCode::VecExpandI
            | OpCode::VecExpandF
            | OpCode::VecLoadI
            | OpCode::VecLoadF
    )
}

/// Returns true if `opcode` is a Vec* float opcode producing F64X2.
fn is_vec_float_producing(opcode: OpCode) -> bool {
    matches!(
        opcode,
        OpCode::VecFloatAdd
            | OpCode::VecFloatSub
            | OpCode::VecFloatMul
            | OpCode::VecFloatTrueDiv
            | OpCode::VecFloatNeg
            | OpCode::VecFloatAbs
            | OpCode::VecFloatXor
            | OpCode::VecF
            | OpCode::VecPackF
            | OpCode::VecExpandF
            | OpCode::VecLoadF
    )
}

/// Pre-scan ops to find positions that produce vector values.
fn build_vec_oprefs(ops: &[Op], num_inputs: usize) -> VecSet<u32> {
    if !USE_NATIVE_SIMD {
        return VecSet::new();
    }
    let mut set = VecSet::new();
    for (op_idx, op) in ops.iter().enumerate() {
        if is_vec_producing_opcode(op.opcode) {
            let vi = op_var_index(op, op_idx, num_inputs) as u32;
            set.insert(vi);
        }
    }
    set
}

/// Pre-scan to find which vector-producing positions have float type (F64X2).
fn build_vec_float_oprefs(ops: &[Op], num_inputs: usize) -> VecSet<u32> {
    if !USE_NATIVE_SIMD {
        return VecSet::new();
    }
    let mut set = VecSet::new();
    for (op_idx, op) in ops.iter().enumerate() {
        if is_vec_float_producing(op.opcode) {
            let vi = op_var_index(op, op_idx, num_inputs) as u32;
            set.insert(vi);
        }
    }
    set
}

/// Resolve an OpRef as a vector value (I64X2). If the OpRef refers to a
/// vector-producing op, uses the variable directly (bitcasting F64X2 to
/// I64X2 if needed). If it's a constant, splats it to fill all lanes.
fn resolve_opref_vec_int(
    builder: &mut FunctionBuilder,
    constants: &majit_ir::VecAssoc<u32, i64>,
    vec_oprefs: &VecSet<u32>,
    vec_float_oprefs: &VecSet<u32>,
    opref: OpRef,
) -> CValue {
    if let Some(c) = lookup_const_i64(constants, opref) {
        let scalar = builder.ins().iconst(cl_types::I64, c);
        return builder.ins().splat(cl_types::I64X2, scalar);
    }
    if vec_oprefs.contains(&opref.raw()) {
        let v = builder.use_var(var(opref.raw()));
        if vec_float_oprefs.contains(&opref.raw()) {
            // Variable is F64X2, bitcast to I64X2
            return builder.ins().bitcast(cl_types::I64X2, MemFlags::new(), v);
        }
        return v;
    }
    // Scalar variable referenced in a vector context: splat it
    let scalar = builder.use_var(var(opref.raw()));
    builder.ins().splat(cl_types::I64X2, scalar)
}

/// Resolve an OpRef as a vector float value (F64X2). If it's a constant,
/// reinterpret the i64 bits as f64 and splat. If it's a vector var,
/// bitcast to F64X2 if needed. If scalar, bitcast to f64 then splat.
fn resolve_opref_vec_float(
    builder: &mut FunctionBuilder,
    constants: &majit_ir::VecAssoc<u32, i64>,
    vec_oprefs: &VecSet<u32>,
    vec_float_oprefs: &VecSet<u32>,
    opref: OpRef,
) -> CValue {
    if let Some(c) = lookup_const_i64(constants, opref) {
        let scalar_i = builder.ins().iconst(cl_types::I64, c);
        let scalar_f = builder
            .ins()
            .bitcast(cl_types::F64, MemFlags::new(), scalar_i);
        return builder.ins().splat(cl_types::F64X2, scalar_f);
    }
    if vec_oprefs.contains(&opref.raw()) {
        let v = builder.use_var(var(opref.raw()));
        if vec_float_oprefs.contains(&opref.raw()) {
            // Already F64X2
            return v;
        }
        // I64X2 -> F64X2 bitcast
        return builder.ins().bitcast(cl_types::F64X2, MemFlags::new(), v);
    }
    // Scalar variable: reinterpret as f64 (a float var is already F64) then splat
    let scalar = builder.use_var(var(opref.raw()));
    let scalar_f = coerce_ty(builder, scalar, cl_types::F64);
    builder.ins().splat(cl_types::F64X2, scalar_f)
}

/// Map a majit Type to the corresponding Cranelift IR type for call signatures.
fn cranelift_type_for(tp: &Type) -> cranelift_codegen::ir::Type {
    match tp {
        Type::Int | Type::Ref => cl_types::I64,
        Type::Float => cl_types::F64,
        Type::Void => cl_types::I64,
    }
}

thread_local! {
    /// `llmodel.py:58` `self.gc_ll_descr = get_ll_description(...)` — owned
    /// by the active cranelift backend on this thread. Stored as a
    /// thread-local so the backend-agnostic `majit_gc::ActiveGcGuardHooks`
    /// shims and trampoline-baked C addresses can reach the live allocator
    /// without taking a cranelift dependency. Mirrors
    /// `majit-backend-dynasm/src/runner.rs:46 DYNASM_ACTIVE_GC`.
    static CRANELIFT_ACTIVE_GC: RefCell<Option<Box<dyn GcAllocator>>> =
        const { RefCell::new(None) };
    static CRANELIFT_ACTIVE_GC_RAW: Cell<Option<*mut dyn GcAllocator>> =
        const { Cell::new(None) };
    /// JITFRAME `Type` id of the active GC runtime. Lazy-registered when
    /// the GC sees its first JITFRAME, cleared when the active GC is
    /// replaced or torn down.
    static CRANELIFT_JITFRAME_TYPE_ID: Cell<Option<u32>> = const { Cell::new(None) };
}

fn with_cranelift_gc<R>(f: impl FnOnce(&mut dyn GcAllocator) -> R) -> Option<R> {
    CRANELIFT_ACTIVE_GC.with(|cell| {
        let mut guard = cell.borrow_mut();
        match guard.as_deref_mut() {
            Some(gc) => Some(f(gc)),
            None => None,
        }
    })
}

fn with_cranelift_gc_required<R>(f: impl FnOnce(&mut dyn GcAllocator) -> R) -> R {
    CRANELIFT_ACTIVE_GC.with(|cell| {
        let mut guard = cell.borrow_mut();
        let gc = guard.as_deref_mut().expect("missing active GC runtime");
        f(gc)
    })
}

fn set_cranelift_active_gc(gc: Option<Box<dyn GcAllocator>>) {
    CRANELIFT_ACTIVE_GC.with(|cell| {
        let mut guard = cell.borrow_mut();
        // Drop the previous allocator first so reentrant
        // `is_managed_heap_object` queries from its drop body still
        // resolve old-heap addresses through the raw mirror — it keeps
        // pointing at the live old box throughout the drop body.
        // Publishing the new raw pointer before the drop would route
        // those queries to the new allocator, which does not know
        // about old-heap addresses and would report them as
        // unmanaged. After the drop returns no further reentry is
        // possible on this thread before the raw mirror is republished
        // synchronously below.
        *guard = gc;
        let raw = guard.as_deref_mut().map(|gc| gc as *mut dyn GcAllocator);
        CRANELIFT_ACTIVE_GC_RAW.with(|raw_cell| raw_cell.set(raw));
    });
}

fn cranelift_jitframe_type_id() -> Option<u32> {
    CRANELIFT_JITFRAME_TYPE_ID.with(|c| c.get())
}

fn set_cranelift_jitframe_type_id(type_id: Option<u32>) {
    CRANELIFT_JITFRAME_TYPE_ID.with(|c| c.set(type_id));
}

fn cranelift_gc_active() -> bool {
    CRANELIFT_ACTIVE_GC.with(|cell| cell.borrow().is_some())
}

/// `majit_gc::CheckIsObjectFn` installed by `set_gc_allocator`. Dispatches
/// `gc.py:631-642 check_is_object` through the thread-local
/// `CRANELIFT_ACTIVE_GC` so backend-agnostic callers (optimizer) can
/// reach the live GC allocator without taking a cranelift dependency.
fn check_is_object_via_active_runtime(gcref: GcRef) -> bool {
    with_cranelift_gc(|gc| gc.check_is_object(gcref)).unwrap_or(false)
}

/// `majit_gc::GetActualTypeidFn` installed by `set_gc_allocator`.
/// Mirrors `gc.py:624-629 get_actual_typeid`: extracts the managed GC
/// header half-word typeid, falling back to the
/// `vtable_to_type_id` table populated via `register_vtable_for_type`
/// for pyre's foreign PyObject layout.
fn get_actual_typeid_via_active_runtime(gcref: GcRef) -> Option<u32> {
    with_cranelift_gc(|gc| gc.get_actual_typeid(gcref)).flatten()
}

/// `majit_gc::CanMoveFn` installed by `set_gc_allocator`. Mirrors
/// `rgc.can_move` (rpython/rlib/rgc.py:229).
fn can_move_via_active_runtime(gcref: GcRef) -> bool {
    with_cranelift_gc(|gc| gc.can_move(gcref)).unwrap_or(false)
}

/// `majit_gc::SubclassRangeFn` installed by `set_gc_allocator`.
/// Resolves the codegen-time `rclass.CLASSTYPE.subclassrange_{min,max}`
/// lookup from x86/assembler.py:1971-1974 through the GC's
/// vtable→typeid table.
fn subclass_range_via_active_runtime(classptr: usize) -> Option<(i64, i64)> {
    with_cranelift_gc(|gc| gc.subclass_range(classptr)).flatten()
}

/// `majit_gc::TypeidSubclassRangeFn` installed by `set_gc_allocator`.
/// Companion to `subclass_range` keyed by typeid — the executor uses
/// it to recover `value.typeptr.subclassrange_min` after extracting
/// the typeid via `get_actual_typeid`.
fn typeid_subclass_range_via_active_runtime(typeid: u32) -> Option<(i64, i64)> {
    with_cranelift_gc(|gc| gc.typeid_subclass_range(typeid)).flatten()
}

/// `majit_gc::TypeidIsObjectFn` installed by `set_gc_allocator`.
/// Answers "does this typeid have `T_IS_RPYTHON_INSTANCE` set in its
/// TYPE_INFO entry" for the executor's `GuardIsObject` arm.
fn typeid_is_object_via_active_runtime(typeid: u32) -> Option<bool> {
    with_cranelift_gc(|gc| gc.typeid_is_object(typeid)).flatten()
}

/// `majit_gc::AllocNurseryTypedFn` installed by `set_gc_allocator`.
/// Routes host-side allocations (pyre-object `w_int_new`, …) through
/// the active cranelift-owned GC. Returns `GcRef(0)` when no active
/// runtime is set on this thread.
///
/// Uses `alloc_nursery_no_collect_typed`: host callers hold a raw
/// `*mut u8` on the Rust stack that is NOT a registered GC root.
/// Triggering a minor collection here would move the nursery object
/// we just returned, leaving the caller dangling. `no_collect` falls
/// back to old-gen on nursery full instead.
fn alloc_nursery_typed_via_active_runtime(type_id: u32, size: usize) -> GcRef {
    with_cranelift_gc(|gc| gc.alloc_nursery_no_collect_typed(type_id, size)).unwrap_or(GcRef(0))
}

/// `majit_gc::AllocOldgenTypedFn` installed by `set_gc_allocator`.
/// Routes host-side allocations that need a stable (non-moving)
/// pointer through the active cranelift-owned GC's old-gen. Used by
/// pyre-object `w_int_new` / `w_float_new` non-cached paths (Task
/// #141) where the caller holds the returned pointer on the Rust
/// stack across subsequent allocations. Returns `GcRef(0)` when no
/// active runtime is set on this thread.
fn alloc_oldgen_typed_via_active_runtime(type_id: u32, size: usize) -> GcRef {
    with_cranelift_gc(|gc| gc.alloc_oldgen_typed(type_id, size)).unwrap_or(GcRef(0))
}

/// User-level `gc.collect()` trampoline — drives `GcAllocator::collect_full`
/// on the active cranelift-owned GC. Mirrors the dynasm equivalent;
/// safety constraints apply (caller must be at a safepoint where every
/// live PyObjectRef is rooted — Rust-stack PyObjectRef in nursery would
/// dangle after the embedded minor cycle).
fn collect_full_via_active_runtime() {
    with_cranelift_gc(|gc| gc.collect_full());
}

/// Host-side root-register trampoline. Bridges
/// `majit_gc::gc_add_root` to the active cranelift-owned GC's
/// `RootSet`.
///
/// # Safety
/// Caller must keep `slot` valid until [`gc_remove_root_via_active_runtime`]
/// is called with the same pointer.
unsafe fn gc_add_root_via_active_runtime(slot: *mut GcRef) {
    with_cranelift_gc(|gc| unsafe { gc.add_root(slot) });
}

/// Companion to [`gc_add_root_via_active_runtime`].
fn gc_remove_root_via_active_runtime(slot: *mut GcRef) {
    with_cranelift_gc(|gc| gc.remove_root(slot));
}

/// Host-side write-barrier trampoline for GC-managed objects updated
/// outside compiled code.
fn gc_write_barrier_via_active_runtime(obj: GcRef) {
    with_cranelift_gc(|gc| gc.write_barrier(obj));
}

/// Host-side `is_managed_heap_object` trampoline. Lets host-side
/// allocators (`pyre_object::dealloc_items_block`) discriminate
/// `try_gc_alloc_stable`-allocated blocks from `std::alloc`-backed
/// fallback blocks during the L1/L2 stepping-stone window.
fn id_or_identityhash_via_active_runtime(addr: usize) -> usize {
    CRANELIFT_ACTIVE_GC.with(|cell| {
        let mut guard = match cell.try_borrow_mut() {
            Ok(guard) => guard,
            Err(_) => return addr,
        };
        match guard.as_deref_mut() {
            Some(gc) => gc.id_or_identityhash(addr),
            None => addr,
        }
    })
}

fn gc_owns_object_via_active_runtime(addr: usize) -> bool {
    CRANELIFT_ACTIVE_GC.with(|cell| {
        let mut guard = match cell.try_borrow_mut() {
            Ok(guard) => guard,
            Err(_) => {
                // Structural adaptation: RPython's GC descriptor can be
                // queried reentrantly while a collection is walking extra
                // roots. Pyre stores the active cranelift GC in a Rust
                // `RefCell`; allocation slowpaths hold the mutable borrow
                // while those root walkers may call
                // `gc_current_object_address`. Use the raw pointer only
                // for this immutable ownership query, matching the
                // read-only nature of RPython's descriptor call, instead
                // of panicking across the extern slowpath.
                return CRANELIFT_ACTIVE_GC_RAW.with(|raw| match raw.get() {
                    Some(ptr) => unsafe { (&*ptr).is_managed_heap_object(addr) },
                    None => false,
                });
            }
        };
        guard
            .as_deref_mut()
            .map(|gc| gc.is_managed_heap_object(addr))
            .unwrap_or(false)
    })
}

/// Returns true when the active GC was present and roots were
/// registered; false when no GC is active and registration was a
/// no-op. Callers pair the bool with `unregister_gc_roots` on Drop.
pub(crate) fn register_gc_roots(roots: &mut [GcRef]) -> bool {
    if roots.is_empty() {
        return false;
    }
    with_cranelift_gc(|gc| {
        for root in roots.iter_mut() {
            unsafe {
                gc.add_root(root as *mut GcRef);
            }
        }
    })
    .is_some()
}

pub(crate) fn unregister_gc_roots(roots: &mut [GcRef]) {
    if roots.is_empty() {
        return;
    }
    with_cranelift_gc(|gc| {
        for root in roots.iter_mut() {
            gc.remove_root(root as *mut GcRef);
        }
    });
}

struct GcRootSlotGuard {
    slots: Vec<*mut GcRef>,
    registered: bool,
}

impl GcRootSlotGuard {
    fn new(slots: Vec<*mut GcRef>) -> Self {
        if slots.is_empty() {
            return Self {
                slots,
                registered: false,
            };
        }
        let registered = with_cranelift_gc(|gc| {
            for &slot in &slots {
                unsafe {
                    gc.add_root(slot);
                }
            }
        })
        .is_some();
        Self { slots, registered }
    }
}

impl Drop for GcRootSlotGuard {
    fn drop(&mut self) {
        if !self.registered {
            return;
        }
        with_cranelift_gc(|gc| {
            for &slot in &self.slots {
                gc.remove_root(slot);
            }
        });
    }
}

fn write_barrier_if_managed(obj: GcRef) {
    if obj.is_null() {
        return;
    }
    with_cranelift_gc(|gc| {
        if gc.is_managed_heap_object(obj.0) {
            gc.write_barrier(obj);
        }
    });
}

thread_local! {
    /// Per-thread CALL_ASSEMBLER target registry.
    ///
    /// RPython `CallAssemblerDescr.loop_token` carries a direct
    /// `JitCellToken` reference, so `handle_call_assembler`
    /// (rewrite.py:665-695) reads metadata via
    /// `loop_token.compiled_loop_token` with no indirection. pyre's
    /// backends emit u64-keyed trampolines, so a `token_number ->
    /// RegisteredLoopTarget` map is a TODO required
    /// for the u64 dispatch. Storing the map thread-locally (matching
    /// `CALL_ASSEMBLER_DEADFRAMES` below) keeps cranelift's per-thread
    /// CA state separated and avoids a process-global registry
    /// (keeps cranelift's per-thread CA state separated).
    static CALL_ASSEMBLER_TARGETS: RefCell<VecAssoc<u64, RegisteredLoopTarget>> =
        RefCell::new(VecAssoc::new());
    /// Per-thread caller->callee result-kind expectations. Same
    /// TODO rationale as `CALL_ASSEMBLER_TARGETS`.
    static CALL_ASSEMBLER_EXPECTATIONS: RefCell<VecAssoc<u64, VecAssoc<CallAssemblerCallerId, u64>>> =
        RefCell::new(VecAssoc::new());
    /// Thread-local deadframe storage for call_assembler results.
    /// Each test thread gets its own isolated registry, preventing
    /// non-deterministic failures from shared global state.
    static CALL_ASSEMBLER_DEADFRAMES: RefCell<VecAssoc<u64, DeadFrame>> = RefCell::new(VecAssoc::new());
    static NEXT_CALL_ASSEMBLER_DEADFRAME_HANDLE: Cell<u64> = const { Cell::new(1) };
}

const CALL_ASSEMBLER_OUTCOME_FINISH: i64 = 0;
const CALL_ASSEMBLER_OUTCOME_DEADFRAME: i64 = 1;

/// Callback to "force" a callee frame through the interpreter when
/// call_assembler hits a guard failure.  The callback takes the
/// callee frame pointer (from fail_args[0]) and runs the interpreter
/// to completion, returning the result as an i64.
static CALL_ASSEMBLER_FORCE_FN: OnceLock<extern "C" fn(i64) -> i64> = OnceLock::new();

/// `compile.py:710-716 resume_in_blackhole(descr, deadframe)` parity:
/// callback to resume execution from the guard failure point using the
/// blackhole interpreter.  Args: `(descr_addr, rebuilt_values_ptr,
/// num_rebuilt, raw_deadframe_ptr, num_raw, guard_exc)` →
/// `Option<result>`.  The receiver recovers the failed descr from
/// `descr_addr` via `Backend::fail_descr_arc_from_addr`
/// (`history.py:125` `cpu.get_latest_descr` parity) and derives
/// green_key / trace_id / fail_index from the descr identity
/// (`descr_owning_jct`).  No surrogate triple crosses the C-ABI.
///
/// `guard_exc` is `cpu.grab_exc_value(deadframe)` (`llmodel.py:240`):
/// the pending exception the `must_save_exception` failure-recovery
/// stub staged into `jf_guard_exc`, handed to the blackhole resume per
/// `blackhole.py:1794 _prepare_resume_from_failure`.  `0` = no pending
/// exception.
static CALL_ASSEMBLER_BLACKHOLE_FN: OnceLock<
    fn(usize, *const i64, usize, *const i64, usize, i64) -> Option<i64>,
> = OnceLock::new();

/// Register a blackhole callback for call_assembler guard failure resume.
/// The trailing `i64` is `cpu.grab_exc_value(deadframe)` (llmodel.py:240):
/// the callee's `jf_guard_exc` slot, forwarded so the blackhole resume can
/// seed `_prepare_resume_from_failure` (blackhole.py:1647).
pub fn register_call_assembler_blackhole(
    f: fn(usize, *const i64, usize, *const i64, usize, i64) -> Option<i64>,
) {
    let _ = CALL_ASSEMBLER_BLACKHOLE_FN.set(f);
}

/// compile.py:701-717 handle_fail callback for call_assembler guard failures.
/// (raw_values_ptr, num_values, descr_addr) -> bridge_compiled.
///
/// `pyjitpl.py:2890 handle_guard_failure(self, resumedescr, deadframe)`
/// receives the descr directly; the C-ABI delivers the same shape via
/// `descr_addr` (recovered to `Arc<dyn FailDescr>` by the receiver)
/// instead of a surrogate `(green_key, trace_id, fail_index)` triple.
static CALL_ASSEMBLER_BRIDGE_FN: OnceLock<fn(*const i64, usize, usize) -> bool> = OnceLock::new();

/// On-demand resume callback: pyre-jit registers this to
/// drive `ResumeDataDirectReader` from the failed descr's `rd_numb` /
/// `rd_consts` / `rd_virtuals` / `rd_pendingfields` so cranelift's
/// `rebuild_state_after_failure` no longer needs a pre-baked
/// `ExitRecoveryLayout`.  Mirrors PyPy's `pyjitpl.py:3424
/// MetaInterp.rebuild_state_after_failure(resumedescr, deadframe)` and
/// the `resume.py:1312 blackhole_from_resumedata` flow where the
/// metainterp drives the decoder and the backend just delivers the
/// deadframe.
///
/// Distinct from `REBUILD_STATE_AFTER_FAILURE` (the boxing-only
/// callback at compiler.rs:2040 that runs AFTER recovery_layout
/// materialisation to wrap raw refs into PyObject pointers).  This
/// callback REPLACES the recovery_layout walker entirely.
///
/// Args: `(descr_addr, outputs, types, bridge_num_inputs) -> bool`.
/// Returns `true` when the on-demand decode handled the descr (in
/// which case `*outputs` has been replaced with the rebuilt vec).
/// Returns `false` for synthetic FINISH / external-JUMP / Done* descrs
/// without a downcastable `ResumeGuardDescr` — callers fall back to
/// the recovery_layout walker.
static RESUMEDATA_DEOPT_FN: OnceLock<fn(usize, &mut Vec<i64>, &[Type], usize) -> bool> =
    OnceLock::new();

/// Register the on-demand resume callback for cranelift deopt
/// materialisation.  pyre-jit calls this during JIT
/// boot alongside `register_call_assembler_blackhole` so the
/// callback is reachable when cranelift consumers migrate off the
/// `ExitRecoveryLayout` cache.
pub fn register_resumedata_deopt(f: fn(usize, &mut Vec<i64>, &[Type], usize) -> bool) {
    let _ = RESUMEDATA_DEOPT_FN.set(f);
}

/// On-demand layout reconstruction callback.  Returns
/// an `ExitRecoveryLayout` for the descr at `descr_addr`, optionally
/// prefixed by `caller_prefix`.  Implementation looks up the
/// metainterp's `StoredExitLayout` cache (keyed by trace_id /
/// fail_index_per_trace) and converts the cached `resume_layout` via
/// `ResumeLayout::to_exit_recovery_layout_with_caller_prefix`.
///
/// Sibling of [`RESUMEDATA_DEOPT_FN`] but returns layout structure
/// instead of replaying deopt — used by `recovery_layout_ref()` to
/// produce `ExitRecoveryLayout` without depending on the meta-side
/// `ResumeGuardDescr.recovery_layout` cache.
///
/// Returns `None` for descrs without a `ResumeGuardDescr` meta_descr
/// (synthetic FINISH / external-JUMP) or when the StoredExitLayout
/// lookup fails (descr not in metainterp cache, e.g. overlay
/// synthetics).  Callers must handle `None`.
static RECOVERY_LAYOUT_FN: OnceLock<
    fn(usize, Option<&ExitRecoveryLayout>) -> Option<ExitRecoveryLayout>,
> = OnceLock::new();

/// Register the on-demand layout reconstruction callback for the
/// Path 1 epic.  pyre-jit calls this during JIT boot alongside
/// `register_resumedata_deopt`.
pub fn register_recovery_layout(
    f: fn(usize, Option<&ExitRecoveryLayout>) -> Option<ExitRecoveryLayout>,
) {
    let _ = RECOVERY_LAYOUT_FN.set(f);
}

/// Dispatch helper consulted by `fail_descr_recovery_layout`.
/// Returns `None` if the callback hasn't been registered yet
/// (cranelift in pure-backend tests without pyre-jit boot); production
/// callers fall through to the metainterp's
/// `trace_layout_ref.recovery_layout` fallback at
/// `pyjitpl/mod.rs:6431`, matching dynasm parity.
pub(crate) fn recovery_layout_via_callback(
    descr_addr: usize,
    caller_prefix: Option<&ExitRecoveryLayout>,
) -> Option<ExitRecoveryLayout> {
    let cb = RECOVERY_LAYOUT_FN.get().copied()?;
    cb(descr_addr, caller_prefix)
}

/// Dispatch entry used by the four runtime-deopt callers
/// (compiler.rs:3185, 3555, 3590, 3717) — drives the on-demand
/// `ResumeDataDirectReader` callback
/// (`cranelift_resumedata_deopt`) which materialises virtuals + replays
/// pending fields straight from `rd_numb` / `rd_consts` / `rd_virtuals`
/// / `rd_pendingfields`, matching `pyjitpl.py:3424
/// MetaInterp.rebuild_state_after_failure(resumedescr, deadframe)` +
/// `resume.py:1312 blackhole_from_resumedata`.  No recovery_layout
/// walker fallback — production code paths always reach a
/// `ResumeGuardDescr` meta_descr with populated `rd_numb`.
///
/// When the callback returns false the descr has neither a
/// `ResumeGuardDescr` meta nor a populated `rd_numb`, which in the
/// current cranelift pipeline only happens for synthetic descrs that
/// never have a bridge attached and therefore never reach this
/// dispatch helper at runtime.  Falling through here panics loudly
/// instead of silently producing stale outputs — fixing the producer
/// (synthesise the meta + populate rd_numb) is the right response,
/// not reviving a backend-local cache.
fn rebuild_state_after_failure_dispatch(
    fail_descr: &DescrRef,
    outputs: &mut Vec<i64>,
    fail_arg_types: &[Type],
    bridge_num_inputs: usize,
) {
    let cb = RESUMEDATA_DEOPT_FN.get().copied().expect(
        "RESUMEDATA_DEOPT_FN not registered — pyre-jit's init_callbacks (eval.rs) must call \
         register_resumedata_deopt before any guard can fail.",
    );
    // `cranelift_resumedata_deopt` recovers the descr via
    // `Backend::fail_descr_arc_from_addr` → `recover_fail_descr_cell`,
    // which requires a `FailDescrCell` thin pointer.  Wrap in a fresh
    // cell and bake its address; the cell stays alive through the
    // callback, and the recovery bumps the refcount.
    let cell = majit_ir::FailDescrCell::wrap(fail_descr.clone());
    let descr_addr = Arc::as_ptr(&cell) as *const () as usize;
    let _ = (fail_arg_types, bridge_num_inputs); // walker path removed
    let ok = cb(descr_addr, outputs, fail_arg_types, bridge_num_inputs);
    drop(cell);
    if !ok {
        let fd = as_fd(fail_descr);
        panic!(
            "cranelift_resumedata_deopt callback returned false for a runtime guard \
             failure — descr's meta_descr is not a ResumeGuardDescr or rd_numb is empty. \
             trace_id={} fail_index_per_trace={} fail_arg_types_len={}",
            fd.trace_id(),
            fd.fail_index_per_trace(),
            fail_arg_types.len(),
        );
    }
}

// Thread-local raw local0 value from CallAssemblerI inputs,
