    #[test]
    fn test_sum_loop() {
        let mut backend = CraneliftBackend::new();

        let inputargs = vec![InputArg::new_int(0), InputArg::new_int(1)];
        let ops = vec![
            mk_op(
                OpCode::Label,
                &[OpRef::input_arg_int(0), OpRef::input_arg_int(1)],
                OpRef::NONE.raw(),
            ),
            mk_op(
                OpCode::IntAdd,
                &[OpRef::input_arg_int(1), OpRef::input_arg_int(0)],
                2,
            ),
            mk_op(
                OpCode::IntSub,
                &[OpRef::input_arg_int(0), OpRef::int_op(100)],
                3,
            ),
            mk_op(OpCode::IntGt, &[OpRef::int_op(3), OpRef::int_op(101)], 4),
            mk_op(OpCode::GuardTrue, &[OpRef::int_op(4)], OpRef::NONE.raw()),
            mk_op(
                OpCode::Jump,
                &[OpRef::int_op(3), OpRef::int_op(2)],
                OpRef::NONE.raw(),
            ),
        ];

        let mut constants: majit_ir::VecAssoc<u32, i64> = majit_ir::VecAssoc::new();
        constants.insert(100, 1i64);
        constants.insert(101, 0i64);
        backend.set_constants(constants);

        let mut token = JitCellToken::new(9);
        backend.compile_loop(&inputargs, &ops, &mut token).unwrap();

        let frame = backend.execute_token(&token, &[Value::Int(100), Value::Int(0)]);
        assert_eq!(backend.get_int_value(&frame, 0), 1);
        assert_eq!(backend.get_int_value(&frame, 1), 5049);
    }

