    #[test]
    fn test_raw_store_and_load_f_roundtrip() {
        let mut backend = CraneliftBackend::new();

        let ad = make_array_descr(0, 8, Type::Float, None);
        let inputargs = vec![InputArg::new_ref(0), InputArg::new_float(1)];
        let ops = vec![
            mk_op(
                OpCode::Label,
                &[OpRef::input_arg_ref(0), OpRef::input_arg_float(1)],
                OpRef::NONE.raw(),
            ),
            mk_op_with_descr(
                OpCode::RawStore,
                &[
                    OpRef::input_arg_ref(0),
                    OpRef::int_op(100),
                    OpRef::input_arg_float(1),
                ],
                OpRef::NONE.raw(),
                ad.clone(),
            ),
            mk_op_with_descr(
                OpCode::RawLoadF,
                &[OpRef::input_arg_ref(0), OpRef::int_op(100)],
                2,
                ad,
            ),
            mk_op(OpCode::Finish, &[OpRef::float_op(2)], OpRef::NONE.raw()),
        ];

        let mut constants: majit_ir::VecAssoc<u32, i64> = majit_ir::VecAssoc::new();
        constants.insert(100, 2);
        backend.set_constants(constants);

        let mut token = JitCellToken::new(99);
        backend.compile_loop(&inputargs, &ops, &mut token).unwrap();

        // 8-byte f64 write at offset 2 needs at least 10 bytes; round up so
        // the buffer also satisfies stricter heap-block layouts on Windows.
        let mut data = vec![0u8; 16];
        let ptr = data.as_mut_ptr() as usize;

        let frame = backend.execute_token(&token, &[Value::Ref(GcRef(ptr)), Value::Float(6.25)]);
        assert!((backend.get_float_value(&frame, 0) - 6.25).abs() < 1e-10);
    }

