    #[test]
    fn test_call_assembler_supports_direct_self_recursive_dispatch() {
        let mut backend = make_call_assembler_backend();

        let inputargs = vec![InputArg::new_int(0)];
        let mut constants: majit_ir::VecAssoc<u32, i64> = majit_ir::VecAssoc::new();
        constants.insert(100, 1);
        constants.insert(101, 0);
        backend.set_constants(constants);

        let mut token = JitCellToken::new(1500_250);
        let ops = vec![
            mk_op(OpCode::Label, &[OpRef::input_arg_int(0)], OpRef::NONE.raw()),
            mk_op(
                OpCode::IntGt,
                &[OpRef::input_arg_int(0), OpRef::int_op(101)],
                1,
            ),
            mk_op(OpCode::GuardTrue, &[OpRef::int_op(1)], OpRef::NONE.raw()),
            mk_op(
                OpCode::IntSub,
                &[OpRef::input_arg_int(0), OpRef::int_op(100)],
                2,
            ),
            mk_op_with_descr(
                OpCode::CallAssemblerI,
                &[OpRef::int_op(2)],
                3,
                make_call_assembler_descr(&token, vec![Type::Int], Type::Int),
            ),
            mk_op(OpCode::IntAdd, &[OpRef::int_op(3), OpRef::int_op(100)], 4),
            mk_op(OpCode::Finish, &[OpRef::int_op(4)], OpRef::NONE.raw()),
        ];
        backend.register_pending_target(token.number, vec![Type::Int], 1, 1, -1);
        backend.compile_loop(&inputargs, &ops, &mut token).unwrap();

        let compiled = token
            .compiled
            .as_ref()
            .unwrap()
            .downcast_ref::<CompiledLoop>()
            .unwrap();
        let guard_descr = &compiled.fail_descrs[0];

        let failed = backend.execute_token(&token, &[Value::Int(0)]);
        let failed_descr = get_latest_descr_from_deadframe(&failed)
            .expect("base-case guard should produce a valid descr");
        let guard_fd = as_fd(guard_descr);
        assert_eq!(failed_descr.fail_index(), guard_fd.fail_index());
        assert_eq!(guard_fd.fail_count(), 1);

        backend.set_constants(majit_ir::VecAssoc::new());
        let bridge_ops = vec![
            mk_op(OpCode::Label, &[OpRef::input_arg_int(0)], OpRef::NONE.raw()),
            mk_op(
                OpCode::Finish,
                &[OpRef::input_arg_int(0)],
                OpRef::NONE.raw(),
            ),
        ];
        backend
            .compile_bridge(failed_descr, &inputargs, &bridge_ops, &token, &[], None)
            .unwrap();

        let frame = backend.execute_token(&token, &[Value::Int(4)]);
        let descr = backend.get_latest_descr(&frame);
        assert!(descr.is_finish());
        assert_eq!(backend.get_int_value(&frame, 0), 4);
        assert_eq!(
            as_fd(guard_descr).fail_count(),
            1,
            "CALL_ASSEMBLER guard with attached bridge should dispatch directly without recounting the original faildescr",
        );

        let raw = backend.execute_token_ints_raw(&token, &[4]);
        assert!(raw.is_finish);
        assert_eq!(raw.outputs, vec![4]);
        assert_eq!(raw.typed_outputs, vec![Value::Int(4)]);
    }

